<div>${$e.po_no?`<div class="ml">PO Number</div><div class="mv">${$e.po_no}</div>`:""} ${$e.place_of_supply?`<div class="ml" style="margin-top:10px">Place of Supply</div><div class="mv">${$e.place_of_supply}</div>`:""}</div>
